const raw = $input.first().json.stdout || '{}';
let result;
try { result = JSON.parse(raw); } catch(e) { return []; }
if (result.status !== 'OK') return [];
const files = result.new_files || [];
if (!files.length) return [];
return files.map(f => ({ json: f }));

// Merge file metadata from upstream into a single item
const dedupRaw = $input.first().json.stdout;
const dedup = JSON.parse(dedupRaw);
// Get the file info from 2 nodes back (Dedup Check has it in binary context)
// We store the file info in the item before the dedup check node
const file = $('Parse New Files').first().json;
return [{ json: { ...file, _dedup: dedup } }];

const raw = $input.first().json.stdout || '{}';
const result = JSON.parse(raw);
if (result.status === 'ERROR') {
  throw new Error('OCR failed: ' + (result.error || 'unknown'));
}
// Read the OCR output file
const fs = require('fs');
const outputPath = result.output;
const ocrData = JSON.parse(fs.readFileSync(outputPath, 'utf8'));

const now = new Date().toISOString();
const year = (ocrData.invoice_date || now).substring(0, 4);
const tabName = `Receipts_${year}`;
const receiptId = `REC-${ocrData.file_id}-${Date.now()}`;

if (ocrData.receipt_type === 'not_a_receipt') {
  return [{ json: { _skip: true, _reason: 'not_a_receipt', file_id: ocrData.file_id, tab: 'Receipts_ERRORS' } }];
}

const lines = ocrData.lines && ocrData.lines.length ? ocrData.lines : [{ line_no: 1, description: 'Unitemized receipt', quantity: null, unit_price_ex_vat: null, vat_rate_pct: null, vat_amount: null, line_total_inc_vat: null }];

// Build one row per line item — header fields repeated on each row
const rows = lines.map(line => [
  receiptId,
  ocrData.receipt_type || '',
  now,
  ocrData.image_url || '',
  ocrData.invoice_date || '',
  ocrData.supplier_name || '',
  ocrData.supplier_address || '',
  ocrData.supplier_vat_reg_no || '',
  ocrData.invoice_number || '',
  line.line_no || '',
  line.description || '',
  line.quantity !== null ? line.quantity : '',
  line.unit_price_ex_vat !== null ? line.unit_price_ex_vat : '',
  line.vat_rate_pct !== null ? line.vat_rate_pct : '',
  line.vat_amount !== null ? line.vat_amount : '',
  line.line_total_inc_vat !== null ? line.line_total_inc_vat : '',
  ocrData.subtotal_ex_vat !== null ? ocrData.subtotal_ex_vat : '',
  ocrData.total_vat !== null ? ocrData.total_vat : '',
  ocrData.total_inc_vat !== null ? ocrData.total_inc_vat : '',
  ocrData.currency || 'EUR',
  '',
  result.status,
  ocrData.ocr_confidence || '',
  ocrData.notes || ''
]);

return [{ json: { rows, tab_name: tabName, receipt_id: receiptId, file_id: ocrData.file_id } }];

const fs = require('fs');
const data = $input.first().json;
if (data._skip) return [{ json: data }];
const rowsFile = `C:\\Users\\bermi\\Projects\\apex\\data\\rows_${data.file_id}.json`;
fs.writeFileSync(rowsFile, JSON.stringify(data.rows));
return [{ json: { ...data, rows_file: rowsFile } }];
